# In Keyboard In DAT - onKeyboardEvent
def onKeyboardEvent(dat, key, character, alt, ctrl, shift, state):
    if character == 'f' and state:
        fb = op('feedback1')
        fb.par.reset = 0 if fb.par.reset else 1

MATERIALS = {'metal': 'pbr_metal', 'glass': 'pbr_glass', 'emissive': 'phong_glow'}

def setMaterial(geoName, materialKey):
    mat = MATERIALS.get(materialKey)
    if mat:
        op(geoName).par.material = mat
        print(f'[Geo] {geoName} material -> {mat}')

# Switch to emissive on beat
setMaterial('geo1', 'emissive')

